import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limiting input length to avoid buffer overflow
        int maxLength = 10;
        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum length of " + maxLength + ". Truncating input...");
            input = input.substring(0, maxLength);
        }

        // Copying input into a properly sized buffer
        char[] buffer = new char[input.length()];
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Input: " + new String(buffer));
    }
}

### Explanation:
